from typing import Optional, List, Dict, Union

import pandas as pd
from pandas.api.types import infer_dtype

from pycelonis.errors import AugmentationTableError
from pycelonis.service.augmentation.service import (
    DataTypes,
    AugmentationService,
    InsertOrUpdateRequestTransport,
    InsertOrUpdateValuesTransport,
    ColumnValue,
    DeleteRequestTransport,
    DeleteTupleTransport,
)
from pycelonis_core.base.base_model import PyCelonisBaseModel
from pycelonis_core.client.client import Client

try:
    from pydantic.v1 import Field  # type: ignore
except ImportError:
    from pydantic import Field  # type: ignore


class AugmentationTable(PyCelonisBaseModel):
    """Augmentation table object to interact with augmentation table specific data integration endpoints."""

    client: Client = Field(..., exclude=True)
    name: str
    """Name of augmentation table."""
    data_model_id: str
    """Id of data model where augmentation table is located."""

    def upsert(self, df: pd.DataFrame) -> None:
        """Upserts data frame to existing augmentation table in data model.

        Args:
            df: DataFrame to upsert to existing augmentation table.

        Examples:
            Upsert new data to augmentation table:
            ```python
            df = pd.DataFrame(
                {
                    "ID": [
                        "aa",
                        "bb",
                        "cc",
                    ],
                    "TEST_COLUMN": [
                        1,
                        2,
                        3,
                    ],
                }
            )

            augmentation_table = data_model.get_augmentation_table(
                "TEST_TABLE"
            )
            augmentation_table.upsert(
                df
            )
            ```
        """
        column_name_data_type_dict = AugmentationTable.infer_data_types(df)
        AugmentationService.post_api_external_v2_compute_augmentation_data_model_id_tables_augmentation_table_name(
            self.client,
            self.data_model_id,
            self.name,
            InsertOrUpdateRequestTransport(
                insert_or_update_values_transports=[
                    InsertOrUpdateValuesTransport(
                        column_values=[
                            ColumnValue(
                                column_name=column_name,
                                data_value={
                                    "value": row[column_name],
                                    "@type": column_name_data_type_dict[column_name],
                                },
                            )
                            for column_name in row.index
                        ]
                    )
                    for _, row in df.iterrows()
                ],
                return_old_values=False,
            ),
        )

    def remove(self, df: pd.DataFrame, key: str) -> None:
        """Removes rows from data frame from existing augmentation table in data model.

        Args:
            df: DataFrame to remove from existing augmentation table.
            key: Primary key to use for removal.

        Examples:
            Remove data from augmentation table:
            ```python
            df = pd.DataFrame(
                {
                    "ID": [
                        "aa",
                        "bb",
                        "cc",
                    ]
                }
            )

            augmentation_table = data_model.get_augmentation_table(
                "TEST_TABLE"
            )
            augmentation_table.remove(
                df, key="ID"
            )
            ```
        """
        if key not in df.columns:
            raise AugmentationTableError(f"Data frame must contain the key column '{key}'")

        column_name_data_type_dict = AugmentationTable.infer_data_types(df)
        AugmentationService.post_api_external_v2_compute_augmentation_data_model_id_tables_augmentation_table_name_delete(
            self.client,
            self.data_model_id,
            self.name,
            DeleteRequestTransport(
                delete_tuple_transports=[
                    DeleteTupleTransport(
                        primary_key_value={"value": row[key], "@type": column_name_data_type_dict[key]}
                    )
                    for _, row in df.iterrows()
                ],
                primary_key_column_name=key,
                return_old_values=False,
            ),
        )

    def delete(self) -> None:
        """Deletes augmentation table."""
        AugmentationService.delete_api_external_v2_compute_augmentation_data_model_id_tables_augmentation_table_name(
            self.client, self.data_model_id, self.name
        )

    def __main_attributes__(self) -> Optional[List[str]]:
        return ["name", "data_model_id"]

    @staticmethod
    def infer_data_types(df: pd.DataFrame, create: bool = False) -> Dict:
        """Returns data types for augmentation table columns based on the provided DataFrame."""
        return {
            column_name: AugmentationTable.infer_data_type(df[column_name], create=create) for column_name in df.columns
        }

    @staticmethod
    def infer_data_type(series: pd.Series, create: bool = False) -> Union[DataTypes, str]:
        """Returns data type for augmentation table columns based on the provided Series.

        If `create` is true, data type for augmentation table creation is returned.
        If `create` is false, data type for upsert, append, remove is returned.
        """
        data_type = infer_dtype(series)

        if data_type in ["string", "categorical"]:
            return DataTypes.CEL_STRING if create else "CelString"
        if data_type == "integer":
            return DataTypes.CEL_INT if create else "CelInteger"
        if data_type in ["floating", "decimal"]:
            return DataTypes.CEL_FLOAT if create else "CelFloat"
        if data_type in ["datetime64", "datetime"]:
            return DataTypes.CEL_DATE if create else "CelDate"

        raise AugmentationTableError(
            f"Data type `{data_type}` of column `{series.name}` not supported. "
            f"Try to convert it to a supported type before creating the table. "
            "Supported types are: `string`, `categorical`, `integer`, `floating`, `decimal`, `datetime64`, `datetime`."
        )
